// Full example: simple orchestrator + compensation sequence (pseudo-Node.js)

class SagaOrchestrator {
  constructor(store) { this.store = store; }

  async start(order) {
    await this.store.save({id: order.id, state: 'started'});
    try {
      await this.call('PaymentSvc.charge', order);
      await this.store.update(order.id, {state: 'charged'});

      await this.call('InventorySvc.reserve', order);
      await this.store.update(order.id, {state: 'reserved'});

      await this.call('ShippingSvc.create', order);
      await this.store.update(order.id, {state: 'shipped'});

      await this.store.update(order.id, {state: 'completed'});
    } catch (err) {
      await this.runCompensations(order);
      await this.store.update(order.id, {state: 'failed', reason: err.message});
      throw err;
    }
  }

  async runCompensations(order) {
    // run compensations in reverse based on persisted state
    const s = await this.store.get(order.id);
    if (s.state === 'reserved' || s.state === 'shipped') {
      await this.call('InventorySvc.release', order).catch(()=>{});
    }
    if (s.state === 'charged') {
      await this.call('PaymentSvc.refund', order).catch(()=>{});
    }
  }

  // simplified call (RPC/event) wrapper
  async call(endpoint, payload) { /* network call with retries & idempotency */ }
}
